87,-0.01890694,0.03464178,0.00172669,-0.04090516,-0.00552540,-0.01020837,-0.01287496,-0.01181721,-0.03046872,-0.02823520,0.00566050,-0.03087654,0.01489767,-0.01119571,-0.01438196,0.00879273]'::vector(1024), now(), now()),
('d0000000-0000-0000-0000-000000000012', 'JOB', 'Geschäftsführer / Business Consulting / Wachstumsgelegenheit', 'Geschäftsführer / Business Consulting / Wachstumsgelegenheit at thexton armstrong Nord und Ost Deutschland.', ARRAY['Remote','Business Consulting'], '{"external_id": "public-job-00002", "requirements_text": "Machen Sie den n\u00e4chsten Schritt und arbeiten Sie mit einem vertrauensw\u00fcrdigen Business Consulting - Executive Mentoring-Netzwerk zusammen. Sind Sie erfolgreich im F\u00fchren von Gesch\u00e4ftseinheiten, mit unternehmerischer Denkweise und einer Leidenschaft daf\u00fcr, kleine und mittelst\u00e4ndische Unternehmen zu unterst\u00fctzen? M\u00f6chten Sie Ihre F\u00fchrungserfahrung als Partner eines vertrauensw\u00fcrdigen Unternehmensberatungs- und Executive Mentoring-Unternehmens nutzen, das KMU in einer der dynamischsten Regionen Deutschlands vorantreibt? thexton armstrong l\u00e4dt leitende F\u00fchrungskr\u00e4fte und erfahrene Unternehmer ein sich als Gesch\u00e4ftsf\u00fchrer / selbstst\u00e4ndiger Partner bei thexton armstrong zu bewerben. \u00dcber uns thexton armstrong ist ein internationales Beratungsnetzwerk, das sich auf Unternehmens-Mentoring und Wachstumsberatung f\u00fcr KMU spezialisiert hat . Seit 2012 haben wir Tausenden von Gesch\u00e4ftsinhabern geholfen, Rentabilit\u00e4t, Resilienz und langfristigen Wertzuwachs durch ein strukturiertes Business-Mentoring-Framework zu st\u00e4rken, das praktische Erfahrung mit messbaren Ergebnissen verbindet. Da wir selbst Unternehmer sind, agieren wir als Franchise, bei dem jeder Partner seine eigene Firma oder Praxis mit begrenzten Anfangskapitalanforderungen f\u00fchrt und ausbaut. Obwohl unabh\u00e4ngig, kann jeder Partner das gesamte Fachwissen und die Dienstleistungen des Partnernetzwerk-Supports nutzen und gleichzeitig sein eigenes Risiko als Partner minimieren. Wir sind derzeit erfolgreich in den Niederlanden, Belgien, S\u00fcddeutschland, der Schweiz und dem Vereinigten K\u00f6nigreich t\u00e4tig und expandieren nun in Nord- und Ostdeutschland sowie bald auch in Westdeutschland . Aufgaben Ihre Chance Dies ist eine seltene Gelegenheit als Equity Partner in einem Netzwerk gleichgesinnter Kollegen unsere Expansion in Deutschland", "skills_required": ["Remote", "Business Consulting"], "work_mode": "ONSITE", "employment_type": "EMPLOYED", "external_url": "https://www.arbeitnow.com/jobs/companies/thexton-armstrong-nord-und-ost-deutschland/geschaftsfuhrer-business-consulting-wachstumsgelegenheit-berlin-16403"}'::jsonb, 'IT', true, '[-0.00641212,-0.02263852,-0.01166783,-0.00491416,-0.02195757,-0.07952696,-0.00319817,-0.05573715,0.06154130,0.00630693,-0.02349795,0.04255634,0.05726771,-0.01004832,-0.03300657,0.05487407,-0.11507747,-0.00077230,-0.06739768,0.05207989,-0.03432246,-0.01454146,-0.05062451,0.02210362,-0.04903469,0.00062543,0.01288822,0.02761408,-0.03261642,-0.06235134,-0.00083916,0.02702990,0.02283836,-0.03054964,0.05988568,-0.01499717,-0.07437769,-0.00622087,0.04064377,0.04006901,-0.00781795,0.04271583,0.05769423,0.00027709,-0.00789334,-0.02162446,-0.00258604,-0.01856800,0.03150313,0.00104967,-0.00556950,0.00042022,-0.04621352,-0.02786007,-0.00068547,-0.00430639,0.03385336,-0.05887288,0.00247908,0.03099067,-0.05470417,0.01129767,-0.07942554,0.06694474,-0.03888503,0.03194342,0.05549036,0.04515375,0.01932855,-0.01072399,0.01819249,-0.01097288,0.01466024,0.04696400,-0.00699394,-0.04331383,0.00367162,-0.00237053,0.03903075,-0.00427908,0.00364848,0.01570483,0.05636561,0.02772913,0.02881846,0.02115631,-0.01062051,0.02650761,0.02084503,-0.06413794,0.01116961,0.01765313,0.00560596,-0.05377243,0.05054418,0.01163800,0.03207709,0.08673739,-0.01529949,-0.01068705,-0.00770352,0.03002474,0.02906622,0.03370260,-0.03571191,0.04637197,-0.05766763,0.01199940,-0.04453332,-0.06417114,-0.01703371,-0.02694016,-0.05332268,0.00010410,-0.02467290,-0.03864729,-0.05537815,-0.00926695,0.02031136,-0.04673246,0.00668716,0.00415357,0.01676705,-0.02132143,-0.06170912,0.